from flask import Flask, request, jsonify
from flask_jwt_extended import JWTManager
from flask_sqlalchemy import SQLAlchemy

app = Flask(__name__)
app.config["JWT_SECRET_KEY"] = "your-secret-key"
jwt = JWTManager(app)
db = SQLAlchemy(app)

class User(db.Model):
    id = db.Column(db.Integer, primary_key=True)
    email = db.Column(db.String(120), unique=True, nullable=False)
    username = db.Column(db.String(80), unique=True, nullable=False)
    role = db.Column(db.String(80), nullable=False)
    account_status = db.Column(db.String(80), nullable=False)
    subscription_tier = db.Column(db.String(80), nullable=False)

@jwt.requires_roles("admin")
def update_user(user_id):
    user = User.query.get(user_id)
    if not user:
        return jsonify({"message": "User not found"}), 404

    # Load the resource by both its identifier and the authenticated user or tenant scope
    current_user = jwt.get_jwt()["user"]
    if current_user["id"] != user_id:
        return jsonify({"message": "Unauthorized to update this user"}), 403

    # Check object-level authorization before returning, updating, or deleting the resource
    if not current_user["role"] == "admin":
        return jsonify({"message": "Admin role required to update this user"}), 403

    # Allowlist which fields can be updated instead of blindly applying all user input
    allowed_fields = ["email", "username", "role", "account_status", "subscription_tier"]
    for field in request.json:
        if field not in allowed_fields:
            return jsonify({"message": f"Field {field} is not updatable"}), 400

    # Enforce role checks for admin-only functionality on the server side
    if current_user["role"] != "admin":
        return jsonify({"message": "Admin role required to update this user"}), 403

    # Update the user record
    for field in request.json:
        setattr(user, field, request.json[field])
    db.session.commit()

    return jsonify({"message": "User updated successfully"}), 200